import argparse
from kafka import KafkaAdminClient

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--topic-names", nargs="+", required=True)
    parser.add_argument("--partitions", type=int, default=1)
    parser.add_argument("--replication-factor", type=int, default=3)
    parser.add_argument("--retention-ms", type=int, default=86400000)
    args = parser.parse_args()

    admin_client = KafkaAdminClient(bootstrap_servers="localhost:9092")

    for topic in args.topic_names:
        try:
            admin_client.create_topics([NewTopic(name=topic, num_partitions=args.partitions, replication_factor=args.replication_factor)])
        except KafkaAdminError as e:
            print("Error creating topic {}: {}".format(topic, e))

    for topic in args.topic_names:
        try:
            admin_client.create_partitions([NewPartition(name=topic, num_partitions=args.partitions)])
        except KafkaAdminError as e:
            print("Error creating partition for topic {}: {}".format(topic, e))

    for topic in args.topic_names:
        try:
            admin_client.alter_configs([ConfigEntry(name=topic, config={"retention.ms": args.retention_ms})])
        except KafkaAdminError as e:
            print("Error altering config for topic {}: {}".format(topic, e))